using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(5, result.TotalPages);
            Assert.Equal(1, result.First());
            Assert.Equal(10, result.Last());
        }

        [Fact]
        public void Create_ReturnsSecondPage()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_LastPageMayHaveFewerItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(3, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_FalseOnFirstPage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_TrueOnSecondPage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_TrueWhenNotOnLastPage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FalseOnLastPage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<int> { 1, 2, 3 };
            var result = new PaginatedList<int>(items, 25, 2, 10);

            Assert.Equal(3, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages); // ceil(25/10)
        }

        [Fact]
        public void TotalPages_RoundsUpCorrectly()
        {
            var source = Enumerable.Range(1, 11).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(2, result.TotalPages); // ceil(11/10) = 2
        }

        [Fact]
        public void SinglePage_HasNoPreviousOrNext()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
            Assert.Equal(1, result.TotalPages);
        }
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            TestHelpers.DrainNotificationQueue();
            _service = new NotificationService();
        }

        public void Dispose()
        {
            _service.Dispose();
            TestHelpers.DrainNotificationQueue();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.False(notification.IsRead);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE, "admin");
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("admin", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesProperMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("Student 'John Doe'", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("Student (ID: 1)", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCreateMessage()
        {
            _service.SendNotification("Course", "10", "Chemistry", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.StartsWith("New ", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesUpdateMessage()
        {
            _service.SendNotification("Course", "10", "Chemistry", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            _service.SendNotification("Course", "10", "Chemistry", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
            Assert.Equal("Department", third.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToApproximatelyNow()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", null, EntityOperation.CREATE, null);
            var notification = _service.ReceiveNotification();

            Assert.Equal("System", notification.CreatedBy);
        }
    }
}

