using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        // Concrete subclass to test abstract Person
        private class TestPerson : Person { }

        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var person = new TestPerson { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", person.FullName);
        }

        [Fact]
        public void FullName_WithEmptyFirstName_ReturnsLastNameCommaEmpty()
        {
            var person = new TestPerson { LastName = "Smith", FirstMidName = "" };
            Assert.Equal("Smith, ", person.FullName);
        }

        [Fact]
        public void FullName_WithEmptyLastName_ReturnsCommaFirstName()
        {
            var person = new TestPerson { LastName = "", FirstMidName = "John" };
            Assert.Equal(", John", person.FullName);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = System.DateTime.Today
            };
            Assert.IsAssignableFrom<Person>(student);
            Assert.Equal("Doe, Jane", student.FullName);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = System.DateTime.Today
            };
            Assert.IsAssignableFrom<Person>(instructor);
            Assert.Equal("Prof, Test", instructor.FullName);
        }
    }
}

