using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests
    {
        private SchoolContext CreateSeededContext()
        {
            var context = TestHelpers.CreateContext();
            TestHelpers.SeedBasicData(context);
            return context;
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.NotEmpty(model);
            // We seeded 3 students with different enrollment dates
            Assert.True(model.All(g => g.StudentCount > 0));
        }

        [Fact]
        public void About_GroupsByEnrollmentDate()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // Our seed data has 3 students with different dates: 2010, 2012, 2013
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Contact_SetsViewBagMessage()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_SetsViewBagMessage()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Contains("permission", (string)controller.ViewBag.Message);
        }

        [Fact]
        public void About_WithNoStudents_ReturnsEmptyList()
        {
            using var context = TestHelpers.CreateContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);

            Assert.Empty(model);
        }
    }
}

using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        public StudentsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
        }

        private SchoolContext CreateSeededContext()
        {
            var context = TestHelpers.CreateContext();
            TestHelpers.SeedBasicData(context);
            return context;
        }

        #region Index

        [Fact]
        public void Index_DefaultSort_ReturnsStudentsOrderedByLastName()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
            // Default sort is by LastName ascending
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_ReturnsStudentsDescending()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_ReturnsStudentsOrderedByDate()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal("Alexander", model[0].LastName); // 2010
            Assert.Equal("Alonso", model[1].LastName);    // 2012
            Assert.Equal("Anand", model[2].LastName);     // 2013
        }

        [Fact]
        public void Index_DateDescSort_ReturnsStudentsOrderedByDateDesc()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal("Anand", model[0].LastName);     // 2013
            Assert.Equal("Alonso", model[1].LastName);    // 2012
            Assert.Equal("Alexander", model[2].LastName); // 2010
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Al", null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal(2, model.Count); // Alexander and Alonso
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            using var context = CreateSeededContext();
