using System;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        public NotificationsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
        }

        private SchoolContext CreateSeededContext()
        {
            var context = TestHelpers.CreateContext();
            TestHelpers.SeedBasicData(context);
            return context;
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsEmptyList()
        {
            using var context = CreateSeededContext();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsItems()
        {
            using var context = CreateSeededContext();
            var controller = new NotificationsController(context);

            // Enqueue a notification via the service
            controller.notificationService.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

            var result = controller.GetNotifications();

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
            // Verify the result value has notifications
            var value = result.Value;
            Assert.NotNull(value);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            using var context = CreateSeededContext();
            var controller = new NotificationsController(context);

            // Enqueue 15 notifications
            for (int i = 0; i < 15; i++)
            {
                controller.notificationService.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = controller.GetNotifications();

            Assert.NotNull(result);
            // After getting notifications, only 5 should remain (15 - 10)
            int remaining = 0;
            while (controller.notificationService.ReceiveNotification() != null)
                remaining++;
            Assert.Equal(5, remaining);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccessJson()
        {
            using var context = CreateSeededContext();
            var controller = new NotificationsController(context);

            var result = controller.MarkAsRead(1);

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = CreateSeededContext();
            var controller = new NotificationsController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_MultipleNotifications_ReturnsInOrder()
        {
            using var context = CreateSeededContext();
            var controller = new NotificationsController(context);

            controller.notificationService.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            controller.notificationService.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);
            controller.notificationService.SendNotification("Department", "3", "Third", EntityOperation.DELETE);

            var result = controller.GetNotifications();

            Assert.NotNull(result);
            // The queue should now be empty since GetNotifications drains it
            Assert.Null(controller.notificationService.ReceiveNotification());
        }

        [Fact]
        public void MarkAsRead_InvalidId_StillReturnsSuccess()
        {
            using var context = CreateSeededContext();
            var controller = new NotificationsController(context);

            // MarkAsRead is a no-op for the in-memory implementation
            var result = controller.MarkAsRead(-1);

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }
    }
}

