namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests
    {
        private SchoolContext CreateSeededContext()
        {
            var context = TestHelpers.CreateContext();
            TestHelpers.SeedBasicData(context);
            return context;
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.NotEmpty(model);
            // We seeded 3 students with different enrollment dates
            Assert.True(model.All(g => g.StudentCount > 0));
        }

        [Fact]
        public void About_GroupsByEnrollmentDate()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // Our seed data has 3 students with different dates: 2010, 2012, 2013
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Contact_SetsViewBagMessage()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_SetsViewBagMessage()
        {
            using var context = CreateSeededContext();
            var controller = new HomeController(context);

            var result = controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Contains("permission", (string)controller.ViewBag.Message);
        }

        [Fact]
        public void About_WithNoStudents_ReturnsEmptyList()
        {
            using var context = TestHelpers.CreateContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);

            Assert.Empty(model);
        }
    }
}

