using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        public StudentsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
        }

        private SchoolContext CreateSeededContext()
        {
            var context = TestHelpers.CreateContext();
            TestHelpers.SeedBasicData(context);
            return context;
        }

        #region Index

        [Fact]
        public void Index_DefaultSort_ReturnsStudentsOrderedByLastName()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
            // Default sort is by LastName ascending
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_ReturnsStudentsDescending()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_ReturnsStudentsOrderedByDate()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal("Alexander", model[0].LastName); // 2010
            Assert.Equal("Alonso", model[1].LastName);    // 2012
            Assert.Equal("Anand", model[2].LastName);     // 2013
        }

        [Fact]
        public void Index_DateDescSort_ReturnsStudentsOrderedByDateDesc()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal("Anand", model[0].LastName);     // 2013
            Assert.Equal("Alonso", model[1].LastName);    // 2012
            Assert.Equal("Alexander", model[2].LastName); // 2010
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Al", null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal(2, model.Count); // Alexander and Alonso
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Carson", null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_ResetsPage()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // When searchString is provided, page should reset to 1
            var result = controller.Index(null, null, "Al", 3) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, "Al", null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal(2, model.Count);
            Assert.Equal("Al", controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            controller.Index(null, null, null, null);

            Assert.Equal("name_desc", controller.ViewBag.NameSortParm);
            Assert.Equal("Date", controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WithDateSort_SetsDateSortParmToDateDesc()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudent()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
            Assert.NotNull(student.Enrollments);
        }

        [Fact]
        public void Details_ValidId_IncludesEnrollmentsWithCourses()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Details(1) as ViewResult;
            var student = result.Model as Student;

            Assert.Equal(2, student.Enrollments.Count);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2024-01-15")
            };

            var result = controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavesStudent()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2024-01-15")
            };

            controller.Create(student);

            Assert.Equal(4, context.Students.Count());
            Assert.True(context.Students.Any(s => s.LastName == "Student"));
        }

        [Fact]
        public void Create_Post_ValidStudent_SendsNotification()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2024-01-15")
            };

            controller.Create(student);

            var notification = controller.notificationService.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("CREATE", notification.Operation);
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student { EnrollmentDate = DateTime.Today };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        [Fact]
        public void Create_Post_MinValueDate_AddsModelError()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ErrorCount > 0);
        }

        [Fact]
        public void Create_Post_DateBefore1753_AddsModelError()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Edit

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_NonExistentId_ReturnsNotFound()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            using var context = CreateSeededContext();
