using System;
using System.IO;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Logging.Abstractions;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly ILogger<CoursesController> _logger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _tempDir = Path.Combine(Path.GetTempPath(), $"contoso_test_{Guid.NewGuid()}");
            Directory.CreateDirectory(_tempDir);

            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _logger = NullLogger<CoursesController>.Instance;
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        private SchoolContext CreateSeededContext()
        {
            var context = TestHelpers.CreateContext();
            TestHelpers.SeedBasicData(context);
            return context;
        }

        private CoursesController CreateController(SchoolContext context)
        {
            return new CoursesController(context, _mockEnv.Object, _logger);
        }

        #region Index

        [Fact]
        public void Index_ReturnsCoursesWithDepartments()
        {
            using var context = CreateSeededContext();
            var controller = CreateController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var courses = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(3, courses.Count);
        }

        #endregion

        #region Details

