            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            using var context = CreateSeededContext();
            var controller = CreateController(context);

            var result = controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(course.Department);
        }

