            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
            var departmentList = controller.ViewBag.DepartmentID as SelectList;
            Assert.NotNull(departmentList);
            Assert.Equal(2, departmentList.Count()); // 2 departments seeded
        }

