            var content = new byte[] { 0xFF, 0xD8, 0xFF }; // Fake JPEG header
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(content.Length);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => s.Write(content, 0, content.Length));

            var result = controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var savedCourse = context.Courses.Find(9999);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.StartsWith("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

