using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        public DepartmentsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
        }

        private SchoolContext CreateSeededContext()
        {
            var context = TestHelpers.CreateContext();
            TestHelpers.SeedBasicData(context);
            return context;
        }

        #region Index

        [Fact]
        public void Index_ReturnsDepartmentsWithAdministrator()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var departments = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Equal(2, departments.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_NonExistentId_ReturnsNotFound()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsDepartment()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_Get_PopulatesInstructorDropdown()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructorList = controller.ViewBag.InstructorID as SelectList;
            Assert.NotNull(instructorList);
            Assert.Equal(2, instructorList.Count());
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2024-01-01"),
                InstructorID = 10
            };

            var result = controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_SavesToDB()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2024-01-01"),
                InstructorID = 10
            };

            controller.Create(department);

            Assert.Equal(3, context.Departments.Count());
            Assert.True(context.Departments.Any(d => d.Name == "Physics"));
        }

        [Fact]
        public void Create_Post_ValidDepartment_SendsNotification()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2024-01-01"),
                InstructorID = 10
            };

            controller.Create(department);

            var notification = controller.notificationService.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Department", notification.EntityType);
            Assert.Equal("CREATE", notification.Operation);
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var department = new Department();

            var result = controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            var instructorList = controller.ViewBag.InstructorID as SelectList;
            Assert.NotNull(instructorList);
        }

        #endregion

        #region Edit

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_NonExistentId_ReturnsNotFound()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
            var instructorList = controller.ViewBag.InstructorID as SelectList;
            Assert.NotNull(instructorList);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);
            var dept = context.Departments.Find(1);
            context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var edited = new Department
            {
                DepartmentID = 1,
                Name = "English Literature",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 10
            };

            var result = controller.Edit(edited) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_SendsUpdateNotification()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);
            var dept = context.Departments.Find(1);
            context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var edited = new Department
            {
                DepartmentID = 1,
                Name = "English Literature",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 10
            };

            controller.Edit(edited);

            var notification = controller.notificationService.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { DepartmentID = 1 };

            var result = controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
            var instructorList = controller.ViewBag.InstructorID as SelectList;
            Assert.NotNull(instructorList);
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_NonExistentId_ReturnsNotFound()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);
            var countBefore = context.Departments.Count();

            var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(countBefore - 1, context.Departments.Count());
        }

        [Fact]
        public void DeleteConfirmed_SendsDeleteNotification()
        {
            using var context = CreateSeededContext();
            var controller = new DepartmentsController(context);

            controller.DeleteConfirmed(1);

            var notification = controller.notificationService.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("DELETE", notification.Operation);
            Assert.Equal("Department", notification.EntityType);
        }

        #endregion
    }
}

