using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        public InstructorsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
        }

        private SchoolContext CreateSeededContext()
        {
            var context = TestHelpers.CreateContext();
            TestHelpers.SeedBasicData(context);
            return context;
        }

        #region Index

        [Fact]
        public void Index_ReturnsInstructorsWithDetails()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Index(10, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Courses);
            Assert.NotEmpty(model.Courses);
            // Instructor 10 (Abercrombie) has course 2021 (Composition)
            Assert.Contains(model.Courses, c => c.CourseID == 2021);
        }

        [Fact]
        public void Index_WithInstructorId_SetsViewBag()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            controller.Index(10, null);

            Assert.Equal(10, (int)controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;
            var model = result.Model as InstructorIndexData;
            var instructors = model.Instructors.ToList();

            Assert.Equal("Abercrombie", instructors[0].LastName);
            Assert.Equal("Fakhouri", instructors[1].LastName);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Details_NonExistentId_ReturnsNotFound()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_Get_ReturnsViewWithCourseData()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(instructor.CourseAssignments);
            var courses = controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(3, courses.Count); // 3 courses seeded
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2024-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructor_SavesToDB()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2024-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            controller.Create(instructor, null);

            Assert.Equal(3, context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2024-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var selectedCourses = new[] { "1050", "4022" };
            controller.Create(instructor, selectedCourses);

            var savedInstructor = context.Instructors
                .Where(i => i.LastName == "Instructor")
                .First();
            var assignments = context.CourseAssignments
                .Where(ca => ca.InstructorID == savedInstructor.ID)
                .ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void Create_Post_ValidInstructor_SendsNotification()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2024-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            controller.Create(instructor, null);

            var notification = controller.notificationService.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("CREATE", notification.Operation);
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
            var courses = controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourseData()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)10) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
            var courses = controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
        }

        [Fact]
        public void Edit_Get_PopulatesCourseDataWithAssignmentFlags()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            controller.Edit((int?)10);

            var courses = controller.ViewBag.Courses as List<AssignedCourseData>;
            // Instructor 10 is assigned to course 2021
            var assignedCourse = courses.Single(c => c.CourseID == 2021);
            Assert.True(assignedCourse.Assigned);
            var unassignedCourse = courses.Single(c => c.CourseID == 1050);
            Assert.False(unassignedCourse.Assigned);
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

