[Fact]
public void GetNotifications_WithNotifications_ReturnsItems()
{
    using var context = CreateSeededContext();
    var controller = new NotificationsController(context);

    // Enqueue a notification via a standalone service (static queue shared)
    using var svc = new NotificationService();
    svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

    var result = controller.GetNotifications();

    Assert.NotNull(result);
    Assert.IsType<JsonResult>(result);
    var value = result.Value;
    Assert.NotNull(value);
}

[Fact]
public void GetNotifications_LimitsTo10()
{
    using var context = CreateSeededContext();
    var controller = new NotificationsController(context);

    // Enqueue 15 notifications via standalone service
    using var svc = new NotificationService();
    for (int i = 0; i < 15; i++)
    {
        svc.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
    }

    var result = controller.GetNotifications();

    Assert.NotNull(result);
    // After getting 10 notifications, only 5 should remain
    int remaining = 0;
    while (svc.ReceiveNotification() != null)
        remaining++;
    Assert.Equal(5, remaining);
}

